import { test, expect } from '@playwright/test';
import { getAdminToken, apiCreateProject, apiCreateApproval } from './helpers/auth';
import { API_BASE } from './config/runtime';

test.describe('Onay Akışı', () => {
  let projectId: string;
  let token: string;

  test.beforeAll(async ({ playwright }) => {
    const request = await playwright.request.newContext();
    token = await getAdminToken(request);
    projectId = await apiCreateProject(request, token, `Onay Test ${Date.now()}`);
    await request.dispose();
  });

  test('bekleyen onay onaylanabilmeli', async ({ page, request }) => {
    const approvalId = await apiCreateApproval(request, token, projectId, 'Test Onayı');
    await page.goto(`/p/${projectId}/approvals`);
    await expect(page.getByTestId(`approvals-card-${approvalId}`)).toBeVisible({ timeout: 10_000 });
    await page.getByTestId(`approvals-card-${approvalId}`).click();
    await page.getByTestId('approvals-btn-approve').click();
    await expect(page.getByTestId('approvals-status-approved')).toBeVisible({ timeout: 10_000 });
  });
});
